class Solution:
    def lengthAfterTransformations(self, s, t):
        MOD = 10 ** 9 + 7
        cur = s
        for _ in range(t):
            nxt = []
            for ch in cur:
                if ch == 'z':
                    nxt.append('ab')
                else:
                    nxt.append(chr(ord(ch) + 1))
            cur = ''.join(nxt)
        return len(cur) % MOD

