class Solution:
    def lengthAfterTransformations(self, s: str, t: int) -> int:
        MOD = 10 ** 9 + 7
        cnt = [0] * 26
        for ch in s:
            cnt[ord(ch) - 97] += 1
        for _ in range(t):
            new_cnt = [0] * 26
            for i in range(26):
                if cnt[i] == 0:
                    continue
                if i == 25:
                    new_cnt[0] = (new_cnt[0] + cnt[i]) % MOD
                    new_cnt[1] = (new_cnt[1] + cnt[i]) % MOD
                else:
                    new_cnt[i + 1] = (new_cnt[i + 1] + cnt[i]) % MOD
            cnt = new_cnt
        return sum(cnt) % MOD

