var lengthAfterTransformations = function(s, t) {
    const MOD = 1000000007;
    const cnt = new Array(26).fill(0);
    for (const ch of s) cnt[ch.charCodeAt(0) - 97]++;
    let cur = cnt;
    for (let step = 0; step < t; step++) {
        const next = new Array(26).fill(0);
        for (let i = 0; i < 26; i++) {
            if (cur[i] === 0) continue;
            if (i === 25) {
                next[0] = (next[0] + cur[i]) % MOD;
                next[1] = (next[1] + cur[i]) % MOD;
            } else {
                next[i + 1] = (next[i + 1] + cur[i]) % MOD;
            }
        }
        cur = next;
    }
    let total = 0;
    for (const v of cur) total = (total + v) % MOD;
    return total;
};
